// Helper function to perform DFS and find if there's a pair with sum S
bool dfs(Node* root, int* values, int* value_count, int k) {
    if (root == NULL) return false;

    for (int i = 0; i < *value_count; i++) {
        if (values[i] == k - root->val) return true;
    }
    values[(*value_count)++] = root->val;

    return dfs(root->left, values, value_count, k) || dfs(root->right, values, value_count, k);
}

// Function to check if there are two nodes with a given sum in BST
void twoSumBST(Node* root, int S) {
    int values[10000]; // To hold node values; adjust size as needed
    int value_count = 0;
    bool check = dfs(root, values, &value_count, S);
    if (check) {
        printf("YES\n");
    } else {
        printf("NO\n");
    }
}

